+        assert!(!treap.contains_key(&2));
+        assert!(treap.contains_key(&3));
+    }
+
+    #[test]
+    fn large_treap() {
+        let mut treap = Treap::new();
+        for i in 0..1000 {
+            treap.insert(i, i * 2);
+        }
+
+        assert_eq!(treap.len(), 1000);
+        assert_eq!(treap.min(), Some((&0, &0)));
