+        assert!(treap.is_empty());
+    }
+
+    #[test]
+    fn string_keys() {
+        let mut treap = Treap::new();
+        treap.insert("banana".to_string(), 1);
+        treap.insert("apple".to_string(), 2);
+        treap.insert("cherry".to_string(), 3);
+
+        assert_eq!(treap.min().map(|(k, _)| k.as_str()), Some("apple"));
